export function canExecuteCard(actor: Actor, ctx: ExecuteCardContext): boolean {
  if (actor.role === 'viewer') return false;
  if (!canReadCard(actor, ctx.card)) return false;
  if (ctx.hasPendingConfirmation) return false;
  return true;
}
